import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"Innovation Credits & Humanities Credits","description":"What innovation credits are, what they are used for, and how to earn them. This article uses the School of Electric Power as an example.","frontmatter":{"lang":"en-US","title":"Innovation Credits & Humanities Credits","description":"What innovation credits are, what they are used for, and how to earn them. This article uses the School of Electric Power as an example.","llm_translated":true},"headers":[],"relativePath":"en/learn/extra/innovation_humanities_scores.md","filePath":"en/learn/extra/innovation_humanities_scores.md","lastUpdated":1784829332000}`),a={name:`en/learn/extra/innovation_humanities_scores.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/extra/innovation_humanities_scores.md for this page in Markdown format</div><h1 id="about-innovation-credits-humanities-credits-requirements" tabindex="-1">About Innovation Credits &amp; Humanities Credits Requirements <a class="header-anchor" href="#about-innovation-credits-humanities-credits-requirements" aria-label="Permalink to “About Innovation Credits &amp; Humanities Credits Requirements”">​</a></h1><p><em>Note: The references and policies cited in this article are based on the School of Electric Power&#39;s 2025 regulations. The content is time-sensitive and may differ between schools. Please check for differences with your own school when referencing this content.</em></p><h2 id="innovation-credits" tabindex="-1">Innovation Credits <a class="header-anchor" href="#innovation-credits" aria-label="Permalink to “Innovation Credits”">​</a></h2><p>Graduation requirement: 4 credits</p><p><strong>How to Earn Them</strong></p><h3 id="_1-lecture-tickets-from-the-university-or-your-school" tabindex="-1">1. Lecture Tickets from the University or Your School <a class="header-anchor" href="#_1-lecture-tickets-from-the-university-or-your-school" aria-label="Permalink to “1. Lecture Tickets from the University or Your School”">​</a></h3><p>Points: Typically 0.2 points per ticket Proof: Original lecture ticket Notes: Low difficulty; can be purchased on the black market Caution: Tickets from other schools are generally not accepted; some schools cap this at no more than 2 points; lecture tickets must be originals — keep them safe for all four years</p><h3 id="_2-research-activities-including-srp-baibuti-climbing-plan-etc" tabindex="-1">2. Research Activities (including SRP, Baibuti Climbing Plan, etc.) <a class="header-anchor" href="#_2-research-activities-including-srp-baibuti-climbing-plan-etc" aria-label="Permalink to “2. Research Activities (including SRP, Baibuti Climbing Plan, etc.)”">​</a></h3><p>Points: 2 points per semester; 4 points per academic year Proof: School-level projects verified via the system; faculty-level projects require a paper certificate from the supervisor Notes: Value depends on the supervisor. Some SRP projects also offer competition opportunities. Caution: Not only system-listed projects count — some supervisors have faculty-level SRP projects. Ask senior students in your school for information and proactively contact professors.</p><h3 id="_3-academic-and-technology-competitions" tabindex="-1">3. Academic and Technology Competitions <a class="header-anchor" href="#_3-academic-and-technology-competitions" aria-label="Permalink to “3. Academic and Technology Competitions”">​</a></h3><p>Points: 0.5 points for participation without awards; 1 point if awarded. Points from different levels of the same competition can be accumulated. Proof: Participation certificate from the organizer; award certificate if applicable Notes: Relatively good value; participate more if you have the bandwidth</p><h3 id="_4-papers-and-patents" tabindex="-1">4. Papers and Patents <a class="header-anchor" href="#_4-papers-and-patents" aria-label="Permalink to “4. Papers and Patents”">​</a></h3><p>See table (appendix, TBD)</p><h2 id="humanities-credits" tabindex="-1">Humanities Credits <a class="header-anchor" href="#humanities-credits" aria-label="Permalink to “Humanities Credits”">​</a></h2><p>Graduation requirement: 2 points (1.5 + 0.5) 1.5 points from participating in cultural/artistic activities; 0.5 points from completing 30 hours of volunteer service on iVolunteer (this portion cannot be substituted by other means)</p><p><strong>How to Earn Them</strong></p><h3 id="_1-humanities-lecture-tickets" tabindex="-1">1. Humanities Lecture Tickets <a class="header-anchor" href="#_1-humanities-lecture-tickets" aria-label="Permalink to “1. Humanities Lecture Tickets”">​</a></h3><p>Points: As specified on the ticket Proof: Lecture ticket (must be stamped) Caution: Admission tickets do not count; tickets issued by other schools or student associations are invalid</p><h3 id="_2-cultural-and-sports-competitions" tabindex="-1">2. Cultural and Sports Competitions <a class="header-anchor" href="#_2-cultural-and-sports-competitions" aria-label="Permalink to “2. Cultural and Sports Competitions”">​</a></h3><p>Points: 0.5 points per event Proof: For participation without awards, a certificate from the event organizer; for award winners, a copy of the award certificate</p><h3 id="_3-university-and-school-sports-meets" tabindex="-1">3. University and School Sports Meets <a class="header-anchor" href="#_3-university-and-school-sports-meets" aria-label="Permalink to “3. University and School Sports Meets”">​</a></h3><p>Points: 0.5 points per year (participating in one school sports meet earns 0.5 points; multiple events do not stack) Proof: Certificate issued by the school&#39;s Youth League Committee or Student Union</p><h3 id="_4-school-sports-meet-parade-squad" tabindex="-1">4. School Sports Meet Parade Squad <a class="header-anchor" href="#_4-school-sports-meet-parade-squad" aria-label="Permalink to “4. School Sports Meet Parade Squad”">​</a></h3><p>Points: 0.5 points (only once across four years) Proof: Name list provided by each class; contact the school&#39;s Student Union Sports Department to prepare the certificate Caution: Being a spectator at the opening or closing ceremony does not count</p><h3 id="_5-school-level-basketball-soccer-and-other-sports-competitions" tabindex="-1">5. School-Level Basketball, Soccer, and Other Sports Competitions <a class="header-anchor" href="#_5-school-level-basketball-soccer-and-other-sports-competitions" aria-label="Permalink to “5. School-Level Basketball, Soccer, and Other Sports Competitions”">​</a></h3><p>Points: 0.5 points (only once across four years) Proof: Name list provided by each class; contact the school&#39;s Student Union Sports Department to prepare the certificate Caution: Points from different sports can be stacked</p><h3 id="_6-school-team-or-university-team-athletes" tabindex="-1">6. School Team or University Team Athletes <a class="header-anchor" href="#_6-school-team-or-university-team-athletes" aria-label="Permalink to “6. School Team or University Team Athletes”">​</a></h3><p>Points: 0.5 points (only once across four years) Proof: Provided by the Youth League Committee or Student Union</p><h3 id="_7-school-organized-welcome-party-talent-show-and-cultural-events" tabindex="-1">7. School-Organized Welcome Party, Talent Show, and Cultural Events <a class="header-anchor" href="#_7-school-organized-welcome-party-talent-show-and-cultural-events" aria-label="Permalink to “7. School-Organized Welcome Party, Talent Show, and Cultural Events”">​</a></h3><p>0.5 points (humanities), proof provided by the Youth League Committee or Student Union</p><h3 id="_8-visits-organized-by-party-branch-or-party-school" tabindex="-1">8. Visits Organized by Party Branch or Party School <a class="header-anchor" href="#_8-visits-organized-by-party-branch-or-party-school" aria-label="Permalink to “8. Visits Organized by Party Branch or Party School”">​</a></h3><p>Only count if they come with innovation or humanities credit vouchers.</p>`,33)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};